#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
int main() {
    int N, K, T;
    scanf("%d %d %d", &N, &K, &T);
    long long *a = (long long *)malloc(N * sizeof(long long));
    for (int i = 0; i < N; i++) {
        scanf("%lld", &a[i]);
    }
    for (int k = 0; k <= K; k++) {
        long long sum = 0;
        for (int x = 0; x <= T; x++) {
            long long f_x_k = 0;
            for (int i = 0; i < N; i++) {
                f_x_k = (f_x_k + (x + a[i]) % MOD) % MOD;
            }
            sum = (sum + f_x_k) % MOD;
        }
        printf("%lld ", sum);
    }
    printf("\n");
    return 0;
}

